+                        prop_assert_eq!(service.state(), &progress::State::Complete);
+                        prop_assert_eq!(ctx.percent, 100.0);
+                    }
+                    Some(_) => {
+                        prop_assert_eq!(service.state(), &progress::State::Idle);
+                    }
+                }
+            }
+        }
+    }
+}

