    /// Derive trend from change if not explicitly set.
    pub fn resolved_trend(&self) -> Option<Trend> {
        self.props.trend.or_else(|| {
            self.props.change.map(|c| {
                if c > 0.0       { Trend::Up }
                else if c < 0.0  { Trend::Down }
                else             { Trend::Neutral }
